  ('h7_goniometrie_diff', 'gonio_plus_quotient', 1, 1, 'Benoem: $t(x) = \sin(x)$ en $n(x) = x$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 1, 2, 'Bepaal $t''(x) = \cos(x)$ en $n''(x) = 1$. Pas de quotiëntregel toe.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 1, 3, '$f''(x) = \dfrac{x\cos(x) - \sin(x)}{x^2}$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 2, 1, 'Benoem: $t(x) = \cos(x)$ en $n(x) = \sin(x)$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 2, 2, 'Bepaal $t''(x) = -\sin(x)$ en $n''(x) = \cos(x)$. Pas de quotiëntregel toe.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 2, 3, '$f''(x) = \dfrac{-\sin(x)\sin(x) - \cos(x)\cos(x)}{\sin^2(x)} = \dfrac{-1}{\sin^2(x)}$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 3, 1, 'Benoem: $t(x) = x + \cos(x)$ en $n(x) = \sin(x)$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 3, 2, 'Bepaal $t''(x) = 1 - \sin(x)$ en $n''(x) = \cos(x)$. Pas de quotiëntregel toe.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 3, 3, '$g''(x) = \dfrac{(1-\sin(x))\sin(x) - (x+\cos(x))\cos(x)}{\sin^2(x)} = \dfrac{\sin(x) - x\cos(x) - 1}{\sin^2(x)}$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 4, 1, 'Benoem: $t(x) = x^2 + \sin(x)$ en $n(x) = \cos(x)$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 4, 2, 'Bepaal $t''(x) = 2x + \cos(x)$ en $n''(x) = -\sin(x)$. Pas de quotiëntregel toe.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 4, 3, '$h''(x) = \dfrac{(2x+\cos(x))\cos(x) - (x^2+\sin(x))(-\sin(x))}{\cos^2(x)} = \dfrac{(2x+\cos(x))\cos(x) + (x^2+\sin(x))\sin(x)}{\cos^2(x)}$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 5, 1, 'Benoem: $t(x) = \cos(3x)$ en $n(x) = \sin(3x)$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 5, 2, 'Bepaal $t''(x) = -3\sin(3x)$ en $n''(x) = 3\cos(3x)$ (kettingregel). Pas de quotiëntregel toe.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 5, 3, '$f''(x) = \dfrac{-3\sin(3x)\sin(3x) - \cos(3x) \cdot 3\cos(3x)}{\sin^2(3x)} = \dfrac{-3}{\sin^2(3x)}$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 6, 1, 'Benoem: $t(x) = \cos(x)$ en $n(x) = 1 - \sin(x)$.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 6, 2, 'Bepaal $t''(x) = -\sin(x)$ en $n''(x) = -\cos(x)$. Pas de quotiëntregel toe.'),
  ('h7_goniometrie_diff', 'gonio_plus_quotient', 6, 3, '$k''(x) = \dfrac{-\sin(x)(1-\sin(x)) - \cos(x)(-\cos(x))}{(1-\sin(x))^2} = \dfrac{-\sin(x)+\sin^2(x)+\cos^2(x)}{(1-\sin(x))^2} = \dfrac{1-\sin(x)}{(1-\sin(x))^2} = \dfrac{1}{1-\sin(x)}$.')
) AS s(topic_slug, cluster_slug, q_order, step_order, description)
JOIN public.topics_new t          ON t.slug    = s.topic_slug
JOIN public.topic_clusters_new tc ON tc.slug   = s.cluster_slug AND tc.topic_id = t.id
JOIN public.questions_new q       ON q.cluster_id = tc.id AND q.order_index = s.q_order;

-- Validatie
SELECT 'question_steps_new' AS tbl, COUNT(*)::text AS n FROM public.question_steps_new;
-- Verwacht: 184 (H2) + 198 (H6) + 119 (H7) = 501

COMMIT;
